#!/usr/bin/env python3 """Comprehensive roundtrip test: parse → codegen → re-parse → execute all 30 fixtures.  Pipeline:   1. Parse fixture .py → IR (graph-ai.json dict)   2. Codegen IR → Python source   3. Re-parse the generated Python → IR2   4. Execute both IR and IR2, compare variables  Success = parse ok + codegen ok + re-parse ok + execution matches """ import sys, os, json from pathlib import Path  sys.path.insert(0, os.path.join(os.path.dirname(__file__), "..", "..")) os.chdir(os.path.join(os.path.dirname(__file__), "..", ".."))  from packages.parser import parse_source from packages.codegen import generate as codegen from services.runtime import execute_ir  FIXTURES_DIR = Path("tests/fixtures/python_subset")  pass_count = 0 fail_count = 0 results: list[tuple[str, str, str, str, str]] = []   def run_fixture(fixture_path: Path) -> tuple[bool, str, str]:     """Run roundtrip on one fixture. Returns (ok, stage, detail)."""     name = fixture_path.stem     src = fixture_path.read_text(encoding="utf-8")      # Stage 1: parse     try:         ir = parse_source(src, filename=str(fixture_path))     except Exception as e:         return False, "PARSE", f"{e}"      # Stage 2: codegen     try:         gen_code = codegen(ir)     except Exception as e:         return False, "CODEGEN", f"{e}"      # Stage 3: re-parse generated code     try:         ir2 = parse_source(gen_code, filename=f"{name}_gen.py")     except Exception as e:         return False, "RE-PARSE", f"{e}\nGenerated code:\n{gen_code}"      # Stage 4: execute both and compare     try:         vars1 = execute_ir(ir)     except Exception as e:         return False, "EXEC-ORIG", f"{e}"      try:         vars2 = execute_ir(ir2)     except Exception as e:         return False, "EXEC-GEN", f"{e}\nGenerated code:\n{gen_code}"      # Compare (only check variables that exist in both)     common_keys = set(vars1.keys()) & set(vars2.keys())     mismatches = []     for k in sorted(common_keys):         v1, v2 = vars1[k], vars2[k]         # Skip module/class/function objects (not easily comparable)         if callable(v1) or callable(v2):             continue         if type(v1).__name__ in ("type", "module"):             continue         if v1 != v2:             mismatches.append(f"{k}: {v1!r} != {v2!r}")      if mismatches:         detail = "MISMATCH: " + "; ".join(mismatches[:3])         return False, "COMPARE", detail      return True, "OK", ""   # ── Run all fixtures ─────────────────────────────────────────────────────  fixture_files = sorted(FIXTURES_DIR.glob("*.py")) print(f"Found {len(fixture_files)} fixtures in {FIXTURES_DIR}\n") print(f"{'Fixture':30s} {'Result':8s} {'Stage':12s} Detail") print("-" * 80)  for fp in fixture_files:     ok, stage, detail = run_fixture(fp)     status = "PASS" if ok else "FAIL"     if ok:         pass_count += 1     else:         fail_count += 1     results.append((fp.stem, status, stage, detail))     print(f"{fp.stem:30s} {status:8s} {stage:12s} {detail[:50]}")  print("-" * 80) print(f"Results: {pass_count} passed, {fail_count} failed out of {len(fixture_files)}")  # ── Show generated code for failures ─────────────────────────────────────  if fail_count > 0:     print("\n=== Failure details ===")     for name, status, stage, detail in results:         if status == "FAIL":             fp = FIXTURES_DIR / f"{name}.py"             src = fp.read_text(encoding="utf-8")             try:                 ir = parse_source(src, filename=str(fp))                 gen = codegen(ir)                 print(f"\n--- {name} (failed at {stage}) ---")                 print(f"Original:\n{src}")                 print(f"Generated:\n{gen}")             except Exception:                 pass  sys.exit(0 if fail_count == 0 else 1)